127	///
128	/// # Examples
129	///
130	/// Run subscriber with callback in the background until the session is closed:
131	/// ```no_run
132	/// # #[tokio::main]
133	/// # async fn main() {
134	/// let session = zenoh::open(zenoh::Config::default()).await.unwrap();
135	/// session
136	///     .declare_subscriber("key/expression")
137	///     .callback(|sample| { println!("Received: {} {:?}", sample.key_expr(), sample.payload()) })
138	///     .background()
139	///     .await
140	///     .unwrap();
141	/// // subscriber runs in the background until the session is closed
142	/// # }
143	/// ```
