150	/// let subscriber = session
151	///     .declare_subscriber("key/expression")
152	///     .with(flume::bounded(32))
153	///     .await
154	///     .unwrap();
155	/// while let Ok(sample) = subscriber.recv_async().await {
156	///     println!("Received: {} {:?}", sample.key_expr(), sample.payload());
157	/// }
158	/// // subscriber is undeclared at the end of the scope
159	/// # }
160	/// ```
