381	    fn undeclare_impl(&mut self) -> ZResult<()> {
382	        // set the flag first to avoid double panic if this function panics
383	        self.undeclare_on_drop = false;
384	        let ids: Vec<Id> = zlock!(self.matching_listeners).drain().collect();
385	        for id in ids {
