523	/// Message priority.
524	///
525	/// If QoS is enabled in the [`Config`](crate::config::Config) (see the boolean
526	/// `transport.<transport_type>.qos` parameter),
527	/// Zenoh keeps one transmission queue per [`Priority`], where all messages in
528	/// the queue have the same [`Priority`]. These queues are serviced in the order of their assigned
529	/// [`Priority`] (i.e. from [`Priority::RealTime`] to [`Priority::Background`]).
530	#[derive(Debug, Default, Copy, Clone, PartialEq, Eq, Hash, Deserialize)]
531	#[repr(u8)]
532	pub enum Priority {
533	    RealTime = 1,
534	    InteractiveHigh = 2,
535	    InteractiveLow = 3,
536	    DataHigh = 4,
537	    #[default]
538	    Data = 5,
539	    DataLow = 6,
540	    Background = 7,
541	}
542	
543	impl Priority {
544	    /// Default
545	    pub const DEFAULT: Self = Self::Data;
546	    /// The lowest Priority
547	    #[zenoh_macros::internal]
548	    pub const MIN: Self = Self::MIN_;
549	    const MIN_: Self = Self::Background;
550	    /// The highest Priority
551	    #[zenoh_macros::internal]
552	    pub const MAX: Self = Self::MAX_;
553	    const MAX_: Self = Self::RealTime;
554	    /// The number of available priorities
555	    #[zenoh_macros::internal]
556	    pub const NUM: usize = 1 + Self::MIN_ as usize - Self::MAX_ as usize;
557	}
558	
559	impl TryFrom<u8> for Priority {
560	    type Error = zenoh_result::Error;
561	
562	    /// A Priority is identified by a numeric value.
563	    /// The lower the value, the higher the priority.
564	    /// The higher the value, the lower the priority.
565	    ///
566	    /// Allowed values are: 1-7.
567	    ///
568	    /// Highest priority: 1
569	    /// Lowest priority: 7
570	    fn try_from(priority: u8) -> Result<Self, Self::Error> {
571	        match priority {
572	            1 => Ok(Priority::RealTime),
573	            2 => Ok(Priority::InteractiveHigh),
574	            3 => Ok(Priority::InteractiveLow),
575	            4 => Ok(Priority::DataHigh),
576	            5 => Ok(Priority::Data),
577	            6 => Ok(Priority::DataLow),
578	            7 => Ok(Priority::Background),
579	            unknown => bail!(
580	                "{} is not a valid priority value. Admitted values are: [{}-{}].",
581	                unknown,
582	                Self::MAX_ as u8,
583	                Self::MIN_ as u8
584	            ),
585	        }
586	    }
587	}
588	
589	impl From<PriorityConf> for Priority {
590	    fn from(value: PriorityConf) -> Self {
591	        match value {
592	            PriorityConf::RealTime => Self::RealTime,
593	            PriorityConf::InteractiveHigh => Self::InteractiveHigh,
594	            PriorityConf::InteractiveLow => Self::InteractiveLow,
595	            PriorityConf::DataHigh => Self::DataHigh,
596	            PriorityConf::Data => Self::Data,
597	            PriorityConf::DataLow => Self::DataLow,
598	            PriorityConf::Background => Self::Background,
599	        }
600	    }
601	}
602	
603	impl From<Priority> for PriorityConf {
604	    fn from(value: Priority) -> Self {
605	        match value {
606	            Priority::RealTime => Self::RealTime,
607	            Priority::InteractiveHigh => Self::InteractiveHigh,
608	            Priority::InteractiveLow => Self::InteractiveLow,
609	            Priority::DataHigh => Self::DataHigh,
610	            Priority::Data => Self::Data,
611	            Priority::DataLow => Self::DataLow,
612	            Priority::Background => Self::Background,
613	        }
614	    }
615	}
