332	    /// Constructs an uninitialized empty Sample.
333	    #[zenoh_macros::internal]
334	    pub fn empty() -> Self {
335	        Sample {
336	            key_expr: KeyExpr::dummy(),
337	            payload: ZBytes::new(),
338	            kind: SampleKind::Put,
339	            encoding: Encoding::default(),
340	            timestamp: None,
341	            qos: QoS::default(),
342	            #[cfg(feature = "unstable")]
