350	    pub(crate) fn from_push(
351	        key_expr: KeyExpr<'static>,
352	        qos: push::ext::QoSType,
353	        body: &mut PushBody,
354	        #[cfg(feature = "unstable")] reliability: Reliability,
355	    ) -> Self {
356	        match body {
357	            PushBody::Put(put) => Self {
358	                key_expr,
359	                payload: mem::take(&mut put.payload).into(),
360	                kind: SampleKind::Put,
361	                encoding: mem::take(&mut put.encoding).into(),
362	                timestamp: put.timestamp,
363	                qos: qos.into(),
364	                #[cfg(feature = "unstable")]
365	                reliability,
366	                #[cfg(feature = "unstable")]
367	                source_info: put.ext_sinfo.map(Into::into),
368	                attachment: mem::take(&mut put.ext_attachment).map(Into::into),
369	            },
370	            PushBody::Del(del) => Self {
371	                key_expr,
372	                payload: Default::default(),
373	                kind: SampleKind::Delete,
374	                encoding: Default::default(),
375	                timestamp: del.timestamp,
376	                qos: qos.into(),
377	                #[cfg(feature = "unstable")]
378	                reliability,
379	                #[cfg(feature = "unstable")]
380	                source_info: del.ext_sinfo.map(Into::into),
381	                attachment: mem::take(&mut del.ext_attachment).map(Into::into),
382	            },
383	        }
384	    }
