387	impl CallbackParameter for Sample {
388	    #[cfg(feature = "unstable")]
389	    type Message<'a> = (
390	        KeyExpr<'static>,
391	        push::ext::QoSType,
392	        &'a mut PushBody,
393	        Reliability,
394	    );
395	    #[cfg(not(feature = "unstable"))]
396	    type Message<'a> = (KeyExpr<'static>, push::ext::QoSType, &'a mut PushBody);
397	
398	    fn from_message(msg: Self::Message<'_>) -> Self {
399	        Self::from_push(
400	            msg.0,
401	            msg.1,
402	            msg.2,
403	            #[cfg(feature = "unstable")]
404	            msg.3,
405	        )
406	    }
407	}
