409	/// Structure containing quality of service data
410	#[derive(Debug, Default, Copy, Clone, Eq, PartialEq)]
411	pub(crate) struct QoS {
412	    inner: QoSType,
413	}
414	
415	#[derive(Debug)]
416	pub(crate) struct QoSBuilder(QoS);
417	
418	impl From<QoS> for QoSBuilder {
419	    fn from(qos: QoS) -> Self {
420	        QoSBuilder(qos)
421	    }
422	}
423	
424	impl From<QoSType> for QoSBuilder {
425	    fn from(qos: QoSType) -> Self {
426	        QoSBuilder(QoS { inner: qos })
427	    }
428	}
429	
430	impl From<QoSBuilder> for QoS {
431	    fn from(builder: QoSBuilder) -> Self {
432	        builder.0
433	    }
434	}
435	
436	#[zenoh_macros::internal_trait]
437	impl QoSBuilderTrait for QoSBuilder {
438	    /// Changes the [`CongestionControl`](crate::qos::CongestionControl) to apply when routing the data.
439	    fn congestion_control(self, congestion_control: CongestionControl) -> Self {
440	        let mut inner = self.0.inner;
441	        inner.set_congestion_control(congestion_control);
442	        Self(QoS { inner })
443	    }
444	
445	    /// Changes the [`Priority`](crate::qos::Priority) to apply when routing the data.
446	    fn priority(self, priority: Priority) -> Self {
447	        let mut inner = self.0.inner;
448	        inner.set_priority(priority.into());
449	        Self(QoS { inner })
450	    }
451	
452	    /// Changes the Express policy to apply when routing the data.
453	    ///
454	    /// When express is set to `true`, then the message will not be batched.
455	    /// This usually has a positive impact on latency but a negative impact on throughput.
456	    fn express(self, is_express: bool) -> Self {
457	        let mut inner = self.0.inner;
458	        inner.set_is_express(is_express);
459	        Self(QoS { inner })
460	    }
461	}
462	
463	impl QoS {
464	    /// Get the [`Priority`] of the message.
465	    pub fn priority(&self) -> Priority {
466	        match Priority::try_from(self.inner.get_priority()) {
467	            Ok(p) => p,
468	            Err(e) => {
469	                tracing::trace!(
470	                    "Failed to convert priority: {}; replacing with default value",
471	                    e.to_string()
472	                );
473	                Priority::default()
474	            }
475	        }
476	    }
477	
478	    /// Get the [`CongestionControl`] applied when routing the data.
479	    pub fn congestion_control(&self) -> CongestionControl {
480	        self.inner.get_congestion_control()
481	    }
482	
483	    /// Gets the express flag value. If `true`, the message is not batched during transmission, in order to reduce latency.
484	    pub fn express(&self) -> bool {
485	        self.inner.is_express()
486	    }
487	}
488	
489	impl From<QoSType> for QoS {
490	    fn from(qos: QoSType) -> Self {
491	        QoS { inner: qos }
492	    }
493	}
494	
495	impl From<QoS> for QoSType {
496	    fn from(qos: QoS) -> Self {
497	        qos.inner
498	    }
499	}
